import React, { useState, useEffect } from "react";
import axios from "axios";

export default function Productos() {
  const [productos, setProductos] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [categoriaAbierta, setCategoriaAbierta] = useState(null);

  const [productoActual, setProductoActual] = useState({
    ProductoID: null,
    Nombre: "",
    Descripcion: "",
    Precio: "",
    Stock: "",
    CategoriaID: "",
    Imagen: null,
  });

  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");
  const [imagenModal, setImagenModal] = useState(null);

  // paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const productosPorPagina = 8;

  useEffect(() => {
    obtenerProductos();
    obtenerCategorias();
  }, []);

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (error) {
      console.error("❌ Error productos:", error);
    }
  };

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error categorías:", error);
    }
  };

  const handleChange = (e) => {
    if (e.target.name === "Imagen") {
      setProductoActual({ ...productoActual, Imagen: e.target.files[0] });
    } else {
      setProductoActual({ ...productoActual, [e.target.name]: e.target.value });
    }
  };

  const abrirModalAgregar = () => {
    setProductoActual({
      ProductoID: null,
      Nombre: "",
      Descripcion: "",
      Precio: "",
      Stock: "",
      CategoriaID: "",
      Imagen: null,
    });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalAgregarDesdeCategoria = (categoriaID) => {
    setProductoActual({
      ProductoID: null,
      Nombre: "",
      Descripcion: "",
      Precio: "",
      Stock: "",
      CategoriaID: categoriaID,
      Imagen: null,
    });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (producto) => {
    setProductoActual({ ...producto, Imagen: null });
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarProducto = async (e) => {
    e.preventDefault();

    try {
      const formData = new FormData();
      Object.entries(productoActual).forEach(([key, value]) => {
        if (value !== null) formData.append(key, value);
      });

      if (modoEdicion) {
        await axios.put(
          `http://localhost:5000/api/productos/${productoActual.ProductoID}`,
          formData,
          { headers: { "Content-Type": "multipart/form-data" } }
        );
      } else {
        await axios.post(
          "http://localhost:5000/api/productos",
          formData,
          { headers: { "Content-Type": "multipart/form-data" } }
        );
      }

      setShowModal(false);
      obtenerProductos();
    } catch (error) {
      console.error("❌ Error guardar:", error);
    }
  };

  const eliminarProducto = async (id) => {
    if (!window.confirm("¿Eliminar producto?")) return;
    await axios.delete(`http://localhost:5000/api/productos/${id}`);
    obtenerProductos();
  };

  // búsqueda + paginación
  const productosFiltrados = productos.filter(
    (p) =>
      p.Nombre.toLowerCase().includes(busqueda.toLowerCase()) ||
      p.Descripcion.toLowerCase().includes(busqueda.toLowerCase())
  );

  const totalPaginas = Math.ceil(productosFiltrados.length / productosPorPagina);
  const inicio = (paginaActual - 1) * productosPorPagina;
  const productosPagina = productosFiltrados.slice(inicio, inicio + productosPorPagina);

  // agrupar productos por categoría
  const categoriasConProductos = categorias.map((cat) => ({
    ...cat,
    productos: productosPagina.filter(
      (p) => p.CategoriaID === cat.CategoriaID
    ),
  }));

  return (
    <div className="container mt-5">

      {/* buscador */}
      <div className="d-flex justify-content-between mb-4">
        <input
          className="form-control w-50"
          placeholder="Buscar producto..."
          value={busqueda}
          onChange={(e) => {
            setBusqueda(e.target.value);
            setPaginaActual(1);
          }}
        />
        <button className="btn btn-success" onClick={abrirModalAgregar}>
          ➕ Producto
        </button>
      </div>

      {/* categorías */}
      {categoriasConProductos.map((cat) => (
        <div key={cat.CategoriaID} className="mb-4">

          {/* header categoría */}
          <div
            className="d-flex justify-content-between align-items-center bg-light p-3 rounded shadow-sm"
            style={{ cursor: "pointer" }}
            onClick={() =>
              setCategoriaAbierta(
                categoriaAbierta === cat.CategoriaID ? null : cat.CategoriaID
              )
            }
          >
            <h5 className="mb-0">{cat.Nombre}</h5>

            <button
              className="btn btn-sm btn-success"
              onClick={(e) => {
                e.stopPropagation();
                abrirModalAgregarDesdeCategoria(cat.CategoriaID);
              }}
            >
              ➕ Producto
            </button>
          </div>

          {/* productos */}
          {categoriaAbierta === cat.CategoriaID && (
            <div className="row g-3 mt-2">
              {cat.productos.map((p) => (
                <div key={p.ProductoID} className="col-md-3">
                  <div className="card h-100 shadow-sm">
                    {p.Imagen && (
                      <img
                        src={`http://localhost:5000/uploads/${p.Imagen}`}
                        alt={p.Nombre}
                        className="card-img-top"
                        style={{ height: 160, objectFit: "cover", cursor: "pointer" }}
                        onClick={() => setImagenModal(p.Imagen)}
                      />
                    )}
                    <div className="card-body">
                      <h6>{p.Nombre}</h6>
                      <p>${p.Precio}</p>
                      <div className="d-flex justify-content-between">
                        <button className="btn btn-warning btn-sm" onClick={() => abrirModalEditar(p)}>✏️</button>
                        <button className="btn btn-danger btn-sm" onClick={() => eliminarProducto(p.ProductoID)}>🗑️</button>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
              {cat.productos.length === 0 && (
                <p className="text-muted text-center mt-3">
                  No hay productos en esta categoría
                </p>
              )}
            </div>
          )}
        </div>
      ))}

      {/* paginación */}
      {totalPaginas > 1 && (
        <nav className="mt-4">
          <ul className="pagination justify-content-center">
            {[...Array(totalPaginas)].map((_, i) => (
              <li key={i} className={`page-item ${paginaActual === i + 1 ? "active" : ""}`}>
                <button className="page-link" onClick={() => setPaginaActual(i + 1)}>
                  {i + 1}
                </button>
              </li>
            ))}
          </ul>
        </nav>
      )}

      {/* modal producto */}
      {showModal && (
        <div className="modal fade show" style={{ display: "block", background: "rgba(0,0,0,.6)" }}>
          <div className="modal-dialog modal-lg modal-dialog-centered">
            <div className="modal-content p-4">
              <h5>{modoEdicion ? "Editar" : "Agregar"} Producto</h5>

              <form onSubmit={guardarProducto}>
                <input className="form-control mb-2" name="Nombre" placeholder="Nombre" onChange={handleChange} value={productoActual.Nombre} required />
                <textarea className="form-control mb-2" name="Descripcion" placeholder="Descripción" onChange={handleChange} value={productoActual.Descripcion} />
                <input className="form-control mb-2" name="Precio" type="number" onChange={handleChange} value={productoActual.Precio} required />
                <input className="form-control mb-2" name="Stock" type="number" onChange={handleChange} value={productoActual.Stock} required />

                <select className="form-select mb-2" name="CategoriaID" value={productoActual.CategoriaID} onChange={handleChange} required>
                  <option value="">Seleccione categoría</option>
                  {categorias.map((c) => (
                    <option key={c.CategoriaID} value={c.CategoriaID}>{c.Nombre}</option>
                  ))}
                </select>

                <input type="file" name="Imagen" className="form-control mb-3" onChange={handleChange} />

                <div className="text-end">
                  <button type="button" className="btn btn-secondary me-2" onClick={() => setShowModal(false)}>Cancelar</button>
                  <button className="btn btn-primary">Guardar</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* modal imagen */}
      {imagenModal && (
        <div className="modal fade show" style={{ display: "block", background: "rgba(0,0,0,.8)" }} onClick={() => setImagenModal(null)}>
          <div className="modal-dialog modal-dialog-centered">
            <img src={`http://localhost:5000/uploads/${imagenModal}`} className="img-fluid rounded" alt="producto" />
          </div>
        </div>
      )}
    </div>
  );
}
